CREATE OR REPLACE FUNCTION fpb_get_telephone (as_memno char , as_type char) RETURNS varchar AS $body$
DECLARE

ls_telephone varchar(1000);

BEGIN
  select  telephone
  into STRICT ls_telephone
  from sc_mem_m_member_address
  where (membership_no = as_memno)
  and (address_type = as_type);
  return ls_telephone;

exception
  when no_data_found then return null;
  when others then CALL spa_dberror('fpb_get_telephone');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
